SELECT customers.name, orders.id
FROM customers
FULL OUTER JOIN orders ON customers.id = orders.customer_id;

const outer = (arr1, arr2) => {
    const result = new Set([...arr1, ...arr2]);
    return Array.from(result);
};
const merged = outer([1, 2], [2, 3]);

